class Solution:
    def minimizeStringValue(self, s):
        import heapq
        from collections import Counter
        freq = Counter(c for c in s if c != '?')
        heap = [(freq.get(chr(ord('a') + i), 0), chr(ord('a') + i)) for i in range(26)]
        heapq.heapify(heap)
        fills = []
        for c in s:
            if c == '?':
                cnt, ch = heapq.heappop(heap)
                fills.append(ch)
                heapq.heappush(heap, (cnt + 1, ch))
        fills.sort()
        res = list(s)
        fi = 0
        for i in range(len(res)):
            if res[i] == '?':
                res[i] = fills[fi]
                fi += 1
        return ''.join(res)

