var minimizeStringValue = function(s) {
    const freq = new Array(26).fill(0);
    for (const c of s) if (c !== '?') freq[c.charCodeAt(0) - 97]++;
    // min-heap: simulate with sorted array since 26 elements
    const fills = [];
    for (const c of s) {
        if (c === '?') {
            let minIdx = 0;
            for (let i = 1; i < 26; i++) {
                if (freq[i] < freq[minIdx] || (freq[i] === freq[minIdx] && i < minIdx)) minIdx = i;
            }
            fills.push(String.fromCharCode(97 + minIdx));
            freq[minIdx]++;
        }
    }
    fills.sort();
    let fi = 0;
    let res = '';
    for (const c of s) {
        if (c === '?') res += fills[fi++];
        else res += c;
    }
    return res;
};
